import{_ as a,o as t,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"When to run evals","description":"","frontmatter":{},"headers":[],"relativePath":"when-to-run-evals.md","filePath":"when-to-run-evals.md"}'),o={name:"when-to-run-evals.md"};function s(i,e,n,u,c,h){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="when-to-run-evals" tabindex="-1">When to run evals <a class="header-anchor" href="#when-to-run-evals" aria-label="Permalink to &quot;When to run evals&quot;">​</a></h1><p>Agent evals are most useful when output quality matters as much as code correctness.</p><h2 id="good-moments-to-run-them" tabindex="-1">Good moments to run them <a class="header-anchor" href="#good-moments-to-run-them" aria-label="Permalink to &quot;Good moments to run them&quot;">​</a></h2><h3 id="on-pull-requests" tabindex="-1">On pull requests <a class="header-anchor" href="#on-pull-requests" aria-label="Permalink to &quot;On pull requests&quot;">​</a></h3><p>Run evals in CI for PRs that change prompts, agent logic, tools, retrieval, or model settings.</p><p>Why:</p><ul><li>Catch behavior regressions before merge</li><li>Keep expected quality stable over time</li><li>Make prompt changes reviewable with pass/fail feedback</li></ul><h3 id="before-releases" tabindex="-1">Before releases <a class="header-anchor" href="#before-releases" aria-label="Permalink to &quot;Before releases&quot;">​</a></h3><p>Run the full <code>tests/AgentEvals</code> suite before deployments.</p><p>Why:</p><ul><li>Validate critical flows after dependency/model updates</li><li>Confirm outputs still meet product expectations</li></ul><h3 id="during-prompt-iteration" tabindex="-1">During prompt iteration <a class="header-anchor" href="#during-prompt-iteration" aria-label="Permalink to &quot;During prompt iteration&quot;">​</a></h3><p>Run a subset locally while editing prompt logic.</p><p>Why:</p><ul><li>Tight feedback loop for faster prompt tuning</li><li>Immediate signal when a change breaks a known behavior</li></ul><h2 id="suggested-cadence" tabindex="-1">Suggested cadence <a class="header-anchor" href="#suggested-cadence" aria-label="Permalink to &quot;Suggested cadence&quot;">​</a></h2><ul><li>Small local run while developing: <code>php artisan ai-evals:run --filter=&quot;...&quot;</code></li><li>Full suite on PR and on merge to <code>master</code></li><li>Optional scheduled nightly run for broader confidence</li></ul><h2 id="cases-where-evals-are-especially-valuable" tabindex="-1">Cases where evals are especially valuable <a class="header-anchor" href="#cases-where-evals-are-especially-valuable" aria-label="Permalink to &quot;Cases where evals are especially valuable&quot;">​</a></h2><ul><li>Customer support answers (policy, compliance, tone)</li><li>Structured outputs that must include key facts</li><li>Agent workflows where wrong wording creates support or legal risk</li><li>High-impact user journeys (checkout, cancellation, refunds)</li></ul>',19)])])}const m=a(o,[["render",s]]);export{p as __pageData,m as default};
